function normalize(value) {
    if (value === undefined || value === null || value === 'undefined') {
        return;
    }
    const parsed = parseInt(value, 10);
    return Number.isNaN(parsed) ? value : parsed;
}

const isValidUrl = (url) => url && typeof url === 'string' && url.trim() !== '' && url !== 'undefined';

function getValue(type, isMiniCart = false) {
    const isMiniCartPage =
        isMiniCart || (isValidUrl(snapOptions.miniCartUrl) && window.location.href.includes(snapOptions.miniCartUrl));

    const timerConfig = {
        timer: {
            miniCart: 'miniCartTimer',
            cart: 'cartTimer',
            pdp: 'pdpTimer',
            base: 'baseTimer'
        },
        delayTime: {
            miniCart: 'miniCartDelayTime',
            cart: 'cartDelayTime',
            pdp: 'pdpDelayTime',
            base: 'baseDelayTime'
        }
    };

    const typeObj = timerConfig[type];

    if (isMiniCartPage) {
        const val = normalize(snapOptions[typeObj.miniCart]);
        if (val !== undefined) return val;
    }

    if (isValidUrl(snapOptions.cartUrl) && window.location.href.includes(snapOptions.cartUrl)) {
        const val = normalize(snapOptions[typeObj.cart]);
        if (val !== undefined) return val;
    }

    const pdpVal = normalize(snapOptions[typeObj.pdp]);
    if (pdpVal !== undefined) return pdpVal;

    return normalize(snapOptions[typeObj.base]);
}

function getTimerValue(isMiniCart = false) {
    return getValue('timer', isMiniCart);
}

function getDelayTimeValue(isMiniCart = false) {
    return getValue('delayTime', isMiniCart);
}

