const isSnapMerchantJSMobile =
    /Android|webOS|iPhone|iPad|iPod|BlackBerry/i.test(navigator.userAgent) ||
    /Android|webOS|iPhone|iPad|iPod|BlackBerry/i.test(navigator.platform);
const getByID = (id) => document.getElementById(id);

let snapTemplate = {
    cartCashbackText: snapOptions.cartCashbackText,
    pdpCashbackText: snapOptions.pdpCashbackText,
    miniCartCashbackText: snapOptions.miniCartCashbackText,
    pdpPopUpCashbackText: snapOptions.pdpPopUpCashbackText,
    miniCartPopUpCashbackText: snapOptions.miniCartPopUpCashbackText,
    cartPopUpCashbackText: snapOptions.cartPopUpCashbackText
};

let cashbackCache = {};

async function fetchCashbackDetails() {
    console.log('Fetching cashback details for order value:', snapOrderValue);
    if (cashbackCache[snapOrderValue]) {
        console.log('Cashback details already fetched.');
        snapOptions.cartCashbackText = cashbackCache[snapOrderValue].cartCashbackText;
        snapOptions.pdpCashbackText = cashbackCache[snapOrderValue].pdpCashbackText;
        snapOptions.miniCartCashbackText = cashbackCache[snapOrderValue].miniCartCashbackText;
        snapOptions.pdpPopUpCashbackText = cashbackCache[snapOrderValue].pdpPopUpCashbackText;
        snapOptions.miniCartPopUpCashbackText = cashbackCache[snapOrderValue].miniCartPopUpCashbackText;
        snapOptions.cartPopUpCashbackText = cashbackCache[snapOrderValue].cartPopUpCashbackText;
    } else {
        if (!snapOptions.cashbackApiUrl || snapOptions.cashbackApiUrl === 'undefined') {
            console.log('Cashback API URL is not defined in snapOptions.');
            return;
        }
        let cashbackData = {
            cashbackAmount: 0,
            cashbackPercentage: 0,
            cashbackPromoId: '',
            ...snapTemplate
        };
        var cashbackApiUrl = `${snapOptions.cashbackApiUrl}/api/pub/promos/eligible?mid=${snapOptions.mid}&orderValue=${snapOrderValue}&bestApplicablePromo=true&origin=checkout`;

        try {
            const response = await fetch(cashbackApiUrl, {
                method: 'GET'
            });

            const data = await response.json();

            const cashbackPromo = (data.bestApplicablePromos || []).filter(
                (promo) => promo.type.toLowerCase() === 'cashback'
            )[0];

            cashbackData.cashbackAmount = cashbackPromo?.amount?.maxAllowed || 0;
            cashbackData.cashbackPercentage = parseInt(cashbackPromo?.amount?.value || 0);
            cashbackData.cashbackPromoId = cashbackPromo?.id || '';

            if (cashbackData.cashbackPercentage > 0 && cashbackData.cashbackAmount > 0) {
                Object.keys(snapTemplate).forEach((key) => {
                    cashbackData[key] = transformCashbackText(snapTemplate[key], cashbackData);
                });
            }
        } catch (error) {
            console.error('Failed to fetch cashback details:', error);
        } finally {
            Object.keys(snapTemplate).forEach((key) => {
                const value = cashbackData[key];

                if (value.includes('$')) {
                    cashbackData[key] = '';
                }
                snapOptions[key] = cashbackData[key];
            });
            cashbackCache[snapOrderValue] = { ...cashbackData };
        }
    }
    updateCashbackWidget(
        window.location.href.includes(snapOptions.cartUrl) ? snapOptions.cartCashbackText : snapOptions.pdpCashbackText
    );
}

let downPayment = 0;
let emi = 0;
let snapOrderValue = 0;
let snapQuantity = 1;
let discountedOrderValue = 0;
let snapDiscountCode = '';
let orderValueNotChange = 0;
let miniCartQuantity = 1;
let showWidgetExpress = false;
async function loadOnPage() {
    updateSnapOptions();
    if (snapOptions.isGTMEnable && snapOptions.isGTMEnable !== 'undefined') {
        dataLayer.push({
            event: 'snapmint_widget_impression',
            properties: {
                merchant_id: snapOptions.mid,
                merchant_name: snapOptions.merchantName
            }
        });
    }
    if (
        snapOptions.miniCartUrl &&
        snapOptions.miniCartUrl !== 'undefined' &&
        window.location.href.includes(snapOptions.miniCartUrl)
    )
        addinMiniCartOnHover();
    if (snapOptions.checkDomain && snapOptions.checkDomain !== 'undefined') {
        if (window.location.href.indexOf(snapOptions.domain) != -1) {
        } else {
            return;
        }
    }
    let priceTag = '';
    if (getByIdOrClassName(snapOptions.priceSaleDivId)) {
        priceTag = getByIdOrClassName(snapOptions.priceSaleDivId);
    } else {
        priceTag = getByIdOrClassName(snapOptions.priceDivId);
    }
    if (
        snapOptions.findAmount &&
        snapOptions.findAmount !== 'undefined' &&
        !window.location.href.includes(snapOptions.cartUrl)
    ) {
        snapOrderValue = parseNum(eval(snapOptions.findAmount)) * snapQuantity;
    } else {
        if (priceTag) {
            snapOrderValue = parseNum(priceTag.innerText) * snapQuantity;
        } else {
            snapOrderValue = productdesc.snapOrderValue;
        }
        if (snapOptions.findCartAmount && snapOptions.findCartAmount != 'undefined') {
            eval(snapOptions.findCartAmount);
        }
    }
    const parsedSnapOrderValue = parseFloat(snapOrderValue);
    if (!Number.isNaN(parsedSnapOrderValue)) {
        snapOrderValue = Math.round(parsedSnapOrderValue);
    }
    if (!priceTag) {
        return;
    }
    if (snapOptions.isCashbackEnabled && snapOptions.isCashbackEnabled === 'true') await fetchCashbackDetails();
    else {
        snapOptions.pdpPopUpCashbackText =
            snapOptions.pdpCashbackText =
            snapOptions.cartCashbackText =
            snapOptions.cartPopUpCashbackText =
            snapOptions.miniCartCashbackText =
            snapOptions.miniCartPopUpCashbackText =
                '';
    }
    if (findPopup() === 0) {
        let element = getByIdOrClassName('#sm-widget-btn');
        if (element) element.parentNode.removeChild(element);
        if (snapOptions.isTwoWidget === 'true') {
            let newElement = getByIdOrClassName('.second_widget_btn');
            if (newElement) newElement.parentNode.removeChild(newElement);
        }
        if (snapOptions.errorWidgetPage && snapOptions.errorWidgetPage !== 'undefined')
            addingErrorWidget(snapOrderValue);
        return;
    } else {
        if (snapOptions.errorWidgetPage && snapOptions.errorWidgetPage !== 'undefined') removingErrorWidget();
    }

    if (priceTag) {
        const minOrderVal = parseNum(snapOptions.plans[0].minAmount);
        let parentDiv = getByIdOrClassName(snapOptions.divId);
        if (checkPdpIsMobile()) parentDiv = getByIdOrClassName(snapOptions.mobileDivId);
        if (minOrderVal > snapOrderValue) {
            let errorWidget = snapOptions.errorWidgetPage;
            getByID('dp').textContent = downPayment;
            parentDiv.innerHTML = errorWidget;
            return;
        }
        if (
            snapOptions.discountPercent &&
            snapOptions.discountPercent !== 'undefined' &&
            snapOptions.showDiscountPercentAll &&
            snapOptions.showDiscountPercentAll !== 'undefined'
        ) {
            snapOrderValue = Math.round(snapOrderValue - snapOrderValue * snapOptions.discountPercent);
        }

        for (let planIndex = 0; planIndex < snapOptions.plans.length; planIndex++) {
            const plan = snapOptions.plans[planIndex];

            if (snapOrderValue >= plan.minAmount && snapOrderValue <= plan.maxAmount) {
                downPayment = Math.round((snapOrderValue * plan.dpPercent) / 100);
                emi = Math.round(parseFloat(snapOrderValue * plan.emiPercent) / 100);
            }
        }

        if (!downPayment) {
            downPayment = snapOrderValue / 10;
        }

        if (!emi) {
            emi = parseFloat(snapOrderValue * 10) / 100.0;
        }
        let widgetPage =
            snapOptions.widgetPriceBreakdown && snapOptions.widgetPriceBreakdown !== 'undefined'
                ? snapGetWidgetHtml(snapOrderValue)
                : snapOptions.widgetPage;
        if (
            !window.location.href.includes(snapOptions.cartUrl) &&
            snapOptions.pdpPayLaterAmount &&
            snapOptions.pdpPayLaterAmount !== 'undefined'
        ) {
            if (snapOrderValue < parseInt(snapOptions.pdpPayLaterAmount)) {
                widgetPage = getPayLaterWidget(snapOptions.pdpPayLaterAmount, snapOptions.widgetPage, 'pdp');
            } else {
                let element = getByIdOrClassName('#sm-widget-btn');
                if (element) element.parentNode.removeChild(element);
                if (snapOptions.isTwoWidget === 'true') {
                    let newElement = getByIdOrClassName('.second_widget_btn');
                    if (newElement) newElement.parentNode.removeChild(newElement);
                }
                widgetPage = snapOptions.widgetPage;
            }
        } else if (
            window.location.href.includes(snapOptions.cartUrl) &&
            snapOptions.cartPayLaterAmount &&
            snapOptions.cartPayLaterAmount !== 'undefined'
        ) {
            widgetPage = getPayLaterWidget(snapOptions.cartPayLaterAmount, snapOptions.widgetPage, 'cart');
        }
        if (snapOptions.changeWidget && snapOptions.changeWidget !== 'undefined' && snapOptions.changeWidget !== null) {
            eval(snapOptions.changeWidget);
        }
        if (snapOptions.urlToShowWidgetExpress && snapOptions.urlToShowWidgetExpress !== 'undefined') {
            if (!window.location.href.includes(snapOptions.cartUrl)) {
                if (changeExpressWidget(snapOptions.urlToShowWidgetExpress)) {
                    widgetPage = snapOptions.widgetExpressUrl;
                    showWidgetExpress = true;
                }
            }
        }
        if (snapOptions.cartWidgetExpressUrl && snapOptions.cartWidgetExpressUrl !== 'undefined') {
            if (window.location.href.includes(snapOptions.cartUrl)) {
                if (checkWhichWidgetToLoad(snapOptions.cartWidgetExpressUrl)) {
                    widgetPage = snapOptions.checkForCartWidget;
                    showWidgetExpress = true;
                } else {
                    showWidgetExpress = false;
                }
            }
        }

        /**  Below if condition will check if there is multiple product on pdp page and if true then it will show widget on all products based on their pricing */

        if (snapOptions.isPDPMultiWidget && snapOptions.isPDPMultiWidget !== undefined) {
            eval(snapOptions.executePDPMultiWidget);
        }

        if (!getByIdOrClassName('#sm-widget-btn')) {
            if (
                snapOptions.unleashAbTest &&
                snapOptions.unleashAbTest !== 'undefined' &&
                !getByIdOrClassName(snapOptions.miniCartDivId) &&
                !window.location.href.includes(snapOptions.cartUrl)
            ) {
                widgetPage = widgetPage.replace(
                    '<div id="sm-widget-btn"',
                    '<div id="sm-widget-btn" style="visibility:hidden !important"'
                );
            } else {
                if (snapOptions.position === 'before') parentDiv.insertAdjacentHTML('beforebegin', widgetPage);
                else parentDiv.insertAdjacentHTML('afterend', widgetPage);

                addingCssStyle(snapOptions.style, '#sm-widget-btn');
                widgetPage = widgetPage.replace(
                    '<div id="sm-widget-btn"',
                    '<div id="sm-widget-btn" style="visibility:visible !important"'
                );
            }
            //adding posthog event for pdp widget
            if (snapOptions.isPosthogEventRequired && snapOptions.isPosthogEventRequired === 'true') {
                // if (!window.location.href.includes(snapOptions.cartUrl)) {
                addPosthogEvent();
                // }
            }
        }
        if (
            snapOptions.unleashAbTest &&
            snapOptions.unleashAbTest !== 'undefined' &&
            !getByIdOrClassName(snapOptions.miniCartDivId) &&
            !window.location.href.includes(snapOptions.cartUrl)
        ) {
            await snapAddUnleashScript();
        }
        // after  the widget is added to DOM, for checking isTwoWidget, pdpCashbackText, cartCashbackText, merchantLogo, addingDynamicPlan, isAbTest, cartWidgetExpressUrl, isCashbackCoupon & pdpPayLaterAmount
        loadDataAfterWidgetLoad();
    }
}

const snapMintPushState = history.pushState;
const snapMintReplaceState = history.replaceState;
function onRouteChange() {
    setTimeout(() => {
        loadOnPage();
        if (
            snapCategoryWidgetInfo &&
            snapCategoryWidgetInfo !== 'undefined' &&
            typeof snapCategoryWidgetInfo === 'string' &&
            document.querySelector(snapCategoryWidgetInfo)
        ) {
            collectionList(snapCategoryWidgetInfo);
        }
        if (window.location.href.includes(snapOptions?.cartUrl)) {
            addChangeEventListener(snapOptions.quantityParentDivId, snapOptions.variantParentDivId, false);
        }
    }, snapOptions.reloadTimer || 0);
}
history.pushState = function (...args) {
    snapMintPushState.apply(this, args);
    onRouteChange();
};
history.replaceState = function (...args) {
    snapMintReplaceState.apply(this, args);
    onRouteChange();
};
window.addEventListener('popstate', onRouteChange);

function transformCashbackText(text, cashbackData) {
    if (!text || text === 'undefined') {
        return '';
    }
    if (!cashbackData.cashbackPercentage || !cashbackData.cashbackAmount) {
        return '';
    }
    return text
        .replace('$percent', `${cashbackData.cashbackPercentage}%`)
        .replace('$maxCashback', `₹${cashbackData.cashbackAmount}`);
}

function loadDataAfterWidgetLoad() {
    if (snapOptions.showPaywidgetEmi == 'true') {
        if (getByID('dp')) getByID('dp').textContent = emi;
    } else {
        if (getByID('dp')) getByID('dp').textContent = downPayment;
    }
    let elementpdp = getByIdOrClassName('#sm-widget-btn');
    elementpdp.setAttribute('data-widget', snapOrderValue);

    if (snapOptions.isTwoWidget === 'true' && !window.location.href.includes(snapOptions.cartUrl)) {
        loadSecondWidget();
    }

    updateCashbackWidget(
        window.location.href.includes(snapOptions.cartUrl) ? snapOptions.cartCashbackText : snapOptions.pdpCashbackText
    );

    if (snapOptions.merchantLogo && snapOptions.merchantLogo !== 'undefined') {
        whiteLabelChange();
    }
    if (snapOptions.addingDynamicPlan && snapOptions.addingDynamicPlan !== 'undefined') {
        addDynamicPlan();
    }
    if (snapOptions.isAbTest && snapOptions.isAbTest !== 'undefined') {
        addDynamicData();
    }
    if (snapOptions.pdpPayLaterAmount && snapOptions.pdpPayLaterAmount !== 'undefined') {
        addDynamicPlanWidget();
    }
    if (snapOptions.isCashbackCoupon && snapOptions.isCashbackCoupon !== 'undefined') {
        if (!window.location.href.includes(snapOptions.cartUrl)) {
            if (!getDynamicJsCookie('snapmintDynamicJscookie')) {
                addClassForAutoMaticCoupon(snapOrderValue);
            }
        }
        if (
            snapOptions.isTest &&
            snapOptions.isTest !== 'undefined' &&
            window.location.href.includes(snapOptions.cartUrl)
        ) {
            if (!getDynamicJsCookie('snapmintDynamicJscookie')) {
                addClassForAutoMaticCoupon(snapOrderValue);
            }
        }
    }
    if (snapOptions.cartWidgetExpressUrl && snapOptions.cartWidgetExpressUrl !== 'undefined') {
        if (window.location.href.includes(snapOptions.cartUrl)) {
            if (showWidgetExpress === false) {
                let element = document.querySelector('#sm-widget-btn.snap_emi_txt');
                if (element) {
                    element.style.border = 'none';
                    element.classList.add('widget_express_on_url');
                }
            }
        }
    }

    if (snapOptions.urlToShowWidgetExpress && snapOptions.urlToShowWidgetExpress !== 'undefined') {
        if (!window.location.href.includes(snapOptions.cartUrl)) {
            if (showWidgetExpress === false) {
                let element = document.querySelector('#sm-widget-btn.snap_emi_txt');
                if (element) {
                    element.style.border = 'none';
                    element.classList.add('widget_express_on_url');
                }
            }
        }
        if (snapOptions.isPdpQuickView && snapOptions.isPdpQuickView !== 'undefined') {
            MiniCartOpen();
        }
    }
    if (snapOptions.personaliseDivId && snapOptions.personaliseDivId !== 'undefined') {
        const radioButtons = document.querySelectorAll(snapOptions.personaliseDivId);
        if (radioButtons && radioButtons.length > 0) {
            radioButtons.forEach((button) => {
                if (button.checked) {
                    if (button.value === 'Yes') {
                        let element = getByIdOrClassName('.snap_emi_txt.snap_emi_txt_wrapper');
                        let element_2_0 = getByIdOrClassName('.snap_emi_txt_wrapper.snap_emi_txt.second_widget_btn');
                        if (element) {
                            element.style.display = 'none';
                            element.style.pointerEvents = 'none';
                        }
                        if (element_2_0) {
                            element_2_0.style.display = 'none';
                            element_2_0.style.pointerEvents = 'none';
                        }
                    }
                }
            });
        }
        if (radioButtons && radioButtons.length > 0) {
            let element = getByIdOrClassName('.snap_emi_txt.snap_emi_txt_wrapper');
            let element_2_0 = getByIdOrClassName('.snap_emi_txt_wrapper.snap_emi_txt.second_widget_btn');
            radioButtons.forEach((button) => {
                button.addEventListener('change', function () {
                    if (
                        (this.value === 'Yes' && this.type === 'radio') ||
                        (this.checked == true && this.type === 'checkbox')
                    ) {
                        if (element) {
                            element.style.display = 'none';
                            element.style.pointerEvents = 'none';
                        }
                        if (element_2_0) {
                            element_2_0.style.display = 'none';
                            element_2_0.style.pointerEvents = 'none';
                        }
                    } else if (
                        (this.value === 'No' && this.type === 'radio') ||
                        (this.checked === false && this.type === 'checkbox')
                    ) {
                        if (element) {
                            element.style.display = 'block';
                            element.style.pointerEvents = 'auto';
                        }
                        if (element_2_0) {
                            element_2_0.style.display = 'block';
                            element_2_0.style.pointerEvents = 'auto';
                        }
                    }
                });
            });
        }
    }
}
function addDynamicPlanWidget() {
    let allDate = document.querySelectorAll('.snap_emi_date_widget');
    if (allDate.length > 0) {
        allDate.forEach((element) => {
            if (snapOptions.fullMonthName && snapOptions.fullMonthName !== 'undefined') {
                element.innerHTML = addMonths(new Date(), 1, true);
            } else {
                element.innerHTML = addMonths(new Date(), 1);
            }
        });
    }
}
function getPayLaterWidget(amount, widgetType, pageType) {
    if (pageType === 'miniCart') {
        if (getByIdOrClassName('.snap_emi_txt_minicart')) {
            let id = getByIdOrClassName('.snap_emi_txt_minicart');
            id.parentNode.removeChild(id);
        }
    } else {
        if (getByIdOrClassName('#sm-widget-btn')) {
            if (snapOptions.pdpPayLaterSecondWidget && snapOptions.pdpPayLaterSecondWidget !== 'undefined') {
                let allElement = document.querySelectorAll('#sm-widget-btn');
                if (allElement.length > 0) {
                    allElement.forEach((element) => {
                        element.parentNode.removeChild(element);
                    });
                }
            } else {
                let id = getByIdOrClassName('#sm-widget-btn');
                id.parentNode.removeChild(id);
            }
        }
    }
    if (snapOptions.payLaterWidgetAmountCheck && snapOptions.payLaterWidgetAmountCheck !== 'undefined') {
        if (pageType === 'miniCart') {
            if (snapOptions.isSubtotalVisible && snapOptions.isSubtotalVisible !== 'undefined') {
                if (parseInt(snapOptions.isSubtotalVisible) > parseInt(snapOptions.pdpPayLaterAmount)) {
                    return widgetType;
                }
            }
        }
        if (parseInt(snapOrderValue) > parseInt(snapOptions.pdpPayLaterAmount)) {
            return widgetType;
        }
    }
    if (amount && snapOptions.plans && snapOptions.plans.length > 0) {
        if (parseInt(snapOrderValue) < parseInt(snapOptions.plans[0].maxAmount)) {
            if (pageType === 'pdp') {
                return snapOptions.pdpPayLaterWidget;
            } else if (pageType === 'cart') {
                return snapOptions.cartPayLaterWidget;
            } else if (pageType === 'miniCart') {
                return snapOptions.miniCartPayLaterWidget;
            }
        } else {
            return widgetType;
        }
    }
    return widgetType;
}
function addDynamicData() {
    let element = getByIdOrClassName('#sm-widget-btn');
    if (element) {
        var queryString = window.location.search;
        var urlParams = new URLSearchParams(queryString);
        var variant = urlParams.get('variant');
        element.setAttribute('data-ga-view-custom', '');
        element.setAttribute('data-ga-view-info-custom', 'product_emi_option');
        element.setAttribute('data-ga-view-payload-custom', '{product_id:' + variant + '}');
    }
}

function getPlan(plan) {
    if (plan < 1 || plan > snapOptions.plans.length) {
        return;
    }
    const tenures = [];
    for (let i = 0; i < plan; i++) {
        tenures.push(snapOptions.plans[i].tenure);
    }
    return tenures.join('/');
}
function addDynamicPlan() {
    const element = document.querySelectorAll('.dynamic_emis');
    if (element && element.length > 0) {
        var emitext = [];
        for (let planIndex = 0; planIndex < snapOptions.plans.length; planIndex++) {
            const plan = snapOptions.plans[planIndex];

            if (snapOrderValue >= plan.minAmount && snapOrderValue <= plan.maxAmount) {
                downPayment = Math.round((snapOrderValue * plan.dpPercent) / 100);
                emi = Math.round(parseFloat(snapOrderValue * plan.emiPercent) / 100);
                emitext.push(plan.tenure);
            }
        }

        var dynam_plna = emitext.toString();
        dynam_plna = dynam_plna.replace(/,/g, '/');

        element.forEach((element) => {
            element.innerHTML = dynam_plna;
        });
    }
}
function addDynamicPlanMiniCart() {
    const element = document.querySelectorAll('.dynamic_emis_minicart');
    if (element && element.length > 0) {
        var emitext = [];
        for (let planIndex = 0; planIndex < snapOptions.plans.length; planIndex++) {
            const plan = snapOptions.plans[planIndex];

            if (snapOrderValue >= plan.minAmount && snapOrderValue <= plan.maxAmount) {
                downPayment = Math.round((snapOrderValue * plan.dpPercent) / 100);
                emi = Math.round(parseFloat(snapOrderValue * plan.emiPercent) / 100);
                emitext.push(plan.tenure);
            }
        }

        var dynam_plna = emitext.toString();
        dynam_plna = dynam_plna.replace(/,/g, '/');

        element.forEach((element) => {
            element.innerHTML = dynam_plna;
        });
    }
}
function addingErrorWidget(snapOrderValue) {
    const minOrderVal = parseNum(snapOptions.plans[0].minAmount);
    if (minOrderVal > snapOrderValue) {
        let parentDiv = getByIdOrClassName(snapOptions.divId);
        if (checkPdpIsMobile()) parentDiv = getByIdOrClassName(snapOptions.mobileDivId);
        let widgetPage = snapOptions.errorWidgetPage;
        if (!getByIdOrClassName('#sm-widget-btn.error_widget')) {
            if (snapOptions.position === 'before') parentDiv.insertAdjacentHTML('beforebegin', widgetPage);
            else parentDiv.insertAdjacentHTML('afterend', widgetPage);
            addingCssStyle(snapOptions.style, '#sm-widget-btn.error_widget');
        }
        getByID('dp').textContent = minOrderVal;
    }
}

function updateCashbackWidget(text) {
    if (text === 'undefined') text = '';
    let element = document.querySelector('.cashback_text_widget');
    if (element) {
        element.style.display = 'block';
        let enterText = document.querySelector('.cashback_text_enter');
        if (enterText) {
            enterText.innerHTML = text;
        }
    }
}

