async function loadUnleashScript() {
    return new Promise((resolve, reject) => {
        let script = document.createElement('script');
        script.src = 'https://unpkg.com/unleash-proxy-client@latest/build/main.min.js';
        script.onload = resolve;
        script.onerror = reject;
        document.body.appendChild(script);
    });
}

async function snapAddUnleashScript() {
    if (
        snapOptions.unleashAbTest &&
        snapOptions.unleashAbTest !== 'undefined' &&
        !window.location.href.includes(snapOptions.cartUrl) &&
        snapUnleashFlag !== ''
    ) {
        snapAbTestTextChange();
        return;
    }
    // Load Unleash script
    try {
        await loadUnleashScript();
    } catch (error) {
        console.error('Failed to load Unleash script:', error);
        snapAbTestTextChange();
        return;
    }

    var config = {
        url: 'https://unleash-proxy-prod.snapmint.com/proxy',
        clientKey: 'proxy-client-key',
        appName: 'my-webapp'
    };
    let id = setTimeout(() => {
        var snapmint_Unleash_client = new unleash.UnleashClient(config);
        snapmint_Unleash_client.on('update', () => {
            snapUnleashFlag = snapmint_Unleash_client?.getVariant('widget_ab_test')?.name;
            if (
                snapOptions.unleashAbTest &&
                snapOptions.unleashAbTest !== 'undefined' &&
                !window.location.href.includes(snapOptions.cartUrl)
            ) {
                snapAbTestTextChange();
            }
        });
        // loadOnPage();
        snapmint_Unleash_client.start();
        clearTimeout(id);
    }, 500);
    if (snapUnleashFlag && snapUnleashFlag === '') {
        clearTimeout(id);
    }
}

function snapAbTestTextChange() {
    let widgetPage = '';
    var snapWidget = document.querySelector('#sm-widget-btn');
    const minOrderVal = parseNum(snapOptions.plans[0].minAmount);
    let parentDiv = getByIdOrClassName(snapOptions.divId);
    if (checkPdpIsMobile()) parentDiv = getByIdOrClassName(snapOptions.mobileDivId);
    if (minOrderVal > snapOrderValue) {
        let errorWidget = snapOptions.errorWidgetPage;
        getByID('dp').textContent = downPayment;
        parentDiv.innerHTML = errorWidget;
        return;
    }
    console.log({ snapUnleashFlag });
    if (snapUnleashFlag && snapOptions[snapUnleashFlag] && snapOptions[snapUnleashFlag] !== 'undefined') {
        widgetPage = snapOptions[snapUnleashFlag];
    } else {
        widgetPage = snapOptions.widgetPage;
        if (
            !window.location.href.includes(snapOptions.cartUrl) &&
            snapOptions.pdpPayLaterAmount &&
            snapOptions.pdpPayLaterAmount !== 'undefined'
        ) {
            widgetPage = getPayLaterWidget(snapOptions.pdpPayLaterAmount, snapOptions.widgetPage, 'pdp');
        } else if (
            window.location.href.includes(snapOptions.cartUrl) &&
            snapOptions.cartPayLaterAmount &&
            snapOptions.cartPayLaterAmount !== 'undefined'
        ) {
            widgetPage = getPayLaterWidget(snapOptions.cartPayLaterAmount, snapOptions.widgetPage, 'cart');
        }
        if (snapOptions.urlToShowWidgetExpress && snapOptions.urlToShowWidgetExpress !== 'undefined') {
            if (!window.location.href.includes(snapOptions.cartUrl)) {
                if (changeExpressWidget(snapOptions.urlToShowWidgetExpress)) {
                    widgetPage = snapOptions.widgetExpressUrl;
                    showWidgetExpress = true;
                }
            }
        }
        if (snapOptions.cartWidgetExpressUrl && snapOptions.cartWidgetExpressUrl !== 'undefined') {
            if (window.location.href.includes(snapOptions.cartUrl)) {
                if (checkWhichWidgetToLoad(snapOptions.cartWidgetExpressUrl)) {
                    widgetPage = snapOptions.checkForCartWidget;
                    showWidgetExpress = true;
                } else {
                    showWidgetExpress = false;
                }
            }
        }
    }
    if (!getByIdOrClassName('#sm-widget-btn') && widgetPage) {
        if (snapOptions.position === 'before') parentDiv.insertAdjacentHTML('beforebegin', widgetPage);
        else parentDiv.insertAdjacentHTML('afterend', widgetPage);
        addingCssStyle(snapOptions.style, '#sm-widget-btn');
        snapWidgetSeenEvent();
        if (snapWidget) {
            snapWidget.style.visibility = 'visible';
        }
    }
    // after Abtest widget is added to DOM, for checking isTwoWidget, pdpCashbackText, cartCashbackText, merchantLogo, addingDynamicPlan, isAbTest, cartWidgetExpressUrl, isCashbackCoupon & pdpPayLaterAmount
    loadDataAfterWidgetLoad();
}

function getFbcParameter() {
    var urlParams = new URLSearchParams(window.location.search);
    return urlParams.get('fbc');
}
function storeFbcParameter() {
    var fbc = getFbcParameter();
    if (fbc) {
        document.cookie = 'snapmintfbc=' + fbc + '; path=/; expires=Fri, 31 Dec 9999 23:59:59 GMT';
    }
}
async function webEngageEvent(eventName, data) {
    if (snapOptions.isWebEngageEnable && snapOptions.isWebEngageEnable !== 'undefined') {
        const webEngageProps = {
            ...data,
            product_variant_id: getFilterd(snapProducts, 'imei1'),
            product_name: getFilterd(snapProducts, 'name'),
            product_quantity: getFilterd(snapProducts, 'quantity'),
            product_price: getFilterd(snapProducts, 'unit_price'),
            product_url: getFilterd(webEngageInfo, 'product_url'),
            product_image: getFilterd(webEngageInfo, 'image_url'),
            product_id: getFilterd(webEngageInfo, 'product_id')
        };
        webengage.track(eventName, webEngageProps);
    }
    if (snapOptions.isMetaPixelEnable && snapOptions.isMetaPixelEnable !== 'undefined') {
        storeFbcParameter();
        if (typeof fbq === 'function') {
            let productData = {};
            if (snapProducts.length > 0 && snapProducts[0].source !== 'cart') {
                const currentUrl = window.location.href;
                const newUrl = currentUrl.split('?')[0] + '.json';
                const response = await fetch(newUrl);
                if (!response.ok) {
                    return;
                }
                productData = await response.json();
            }
            const props = {
                content_category: productData?.product?.product_type || null,
                content_ids: getFilterd(webEngageInfo, 'product_id'),
                content_name: getFilterd(snapProducts, 'name'),
                content_type: 'product_group',
                currency: 'INR',
                value: data.order_value
            };
            if (getDynamicJsCookie('snapmintfbc')) {
                props['fbc'] = getDynamicJsCookie('snapmintfbc');
            }
            fbq('track', 'InitiateCheckout', props);
            if (snapProducts.length > 0 && snapProducts[0].source === 'cart') {
                fbq('track', 'AddToCart', props);
            }
        }
    }
}
function getFilterd(data, key) {
    let value = [];
    data.forEach((element) => {
        value.push(element[key]);
    });
    return value;
}
if (snapOptions.isCategory_scrollable && snapOptions.isCategory_scrollable !== 'undefined') {
    if (snapOptions.checkTouchMove && snapOptions.checkTouchMove !== 'undefined') {
        window.addEventListener(
            'touchmove',
            function (e) {
                var currentY = window.scrollY;
                setTimeout(function () {
                    var deltaY = window.scrollY - currentY;
                    handleScroll(deltaY);
                }, 0);
            },
            { passive: true }
        );
    }
    window.addEventListener('wheel', function (e) {
        handleScroll(e.deltaY);
    });
    function handleScroll(deltaY) {
        if (deltaY >= 0) {
            var divId = snapOptions.isCategory_scrollable;
            var addToCollectionList = document.querySelectorAll(divId);
            if (addToCollectionList) {
                addToCollectionList.forEach(function (k) {
                    if (
                        k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice) &&
                        k.querySelector(divId + ' ' + snapOptions.categoryWidgetDivId)
                    ) {
                        try {
                            if (!k.querySelector('.snap_dp_list')) {
                                snapOptions.categoryWidgetInfo = divId;
                                collectionList(divId);
                                snapOptions.categoryWidgetInfo = '';
                            }
                        } catch (e) {
                            console.log(e);
                        }
                    }
                });
            }
        }
    }
}

const getCategoryWidgetHtml = (snapOrderValue, categorySelector) => {
    const priceArray = getPriceArray();
    const isCategoryPage = getByIdOrClassName(categorySelector);

    if (isCategoryPage) {
        return getWidgetForPriceRange(snapOrderValue, priceArray, 'categoryWidget', snapOptions.categoryWidget2);
    }
};

function collectionList(divId) {
    var addToCollectionList = document.querySelectorAll(divId);
    let changeEvent = 'change';
    if (snapOptions.changeEventForCategory && snapOptions.changeEventForCategory !== 'undefined') {
        changeEvent = snapOptions.changeEventForCategory;
    }
    if (addToCollectionList) {
        addToCollectionList.forEach(function (k) {
            if (
                k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice) &&
                k.querySelector(divId + ' ' + snapOptions.categoryWidgetDivId)
            ) {
                try {
                    if (!k.querySelector('.snap_dp_list')) {
                        var Prodprice;
                        if (
                            snapOptions.isNestedCategoryItemPrice &&
                            snapOptions.isNestedCategoryItemPrice !== 'undefined'
                        ) {
                            let regexPattern = snapOptions.getNestedCategoryPriceRegex.slice(1, -1);
                            let regex = new RegExp(regexPattern);
                            Prodprice = getNestedCategoryPrice(
                                k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice).innerText,
                                regex
                            );
                        } else {
                            Prodprice = parseNum(
                                k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice).innerText
                            );
                        }
                        if (
                            Prodprice >= snapOptions.plans[0].minAmount &&
                            Prodprice <= snapOptions.plans[snapOptions.plans.length - 1].maxAmount
                        ) {
                            var SnapWidgetDiv = document.createElement('div');
                            SnapWidgetDiv.className = 'snap_dp_list';
                            SnapWidgetDiv.innerHTML =
                                snapOptions.widgetPriceBreakdown && snapOptions.widgetPriceBreakdown !== 'undefined'
                                    ? getCategoryWidgetHtml(Prodprice, divId)
                                    : snapOptions.categoryWidgetHtml;
                            k.querySelector(divId + ' ' + snapOptions.categoryWidgetDivId).after(SnapWidgetDiv);
                            let popupType = 3;
                            getDownPaymentAndEmi(Prodprice);
                            if (snapOptions.categoryPopupType && snapOptions.categoryPopupType !== 'undefined') {
                                popupType = parseInt(snapOptions.categoryPopupType);
                            }
                            k.querySelector('.snap_dp_list' + ' ' + '.dp-collection-price').innerText = parseNum(emi);
                            k.querySelector('.snap_dp_list' + ' ' + '.dp-collection-price').setAttribute(
                                'data-price',
                                parseNum(Prodprice)
                            );
                            if (
                                snapOptions.changeCategoryWidget &&
                                snapOptions.changeCategoryWidget !== 'undefined' &&
                                snapOptions.changeCategoryWidget !== null
                            ) {
                                eval(snapOptions.changeCategoryWidget);
                            }
                        }
                        if (snapOptions.categoryVariationForm && snapOptions.categoryVariationForm !== 'undefined') {
                            k.querySelector(snapOptions.categoryVariationForm).addEventListener(
                                changeEvent,
                                function (event) {
                                    setTimeout(() => {
                                        if (k.querySelector('.snap_dp_list')) {
                                            k.querySelector('.snap_dp_list').remove();
                                        }

                                        var Prodprice;
                                        if (
                                            snapOptions.isNestedCategoryItemPrice &&
                                            snapOptions.isNestedCategoryItemPrice !== 'undefined'
                                        ) {
                                            let regexPattern = snapOptions.getNestedCategoryPriceRegex.slice(1, -1);
                                            let regex = new RegExp(regexPattern);
                                            Prodprice = getNestedCategoryPrice(
                                                k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice)
                                                    .innerText,
                                                regex
                                            );
                                        } else {
                                            Prodprice = parseNum(
                                                k.querySelector(divId + ' ' + snapOptions.categoryWidgetPrice).innerText
                                            );
                                        }
                                        if (
                                            Prodprice >= snapOptions.plans[0].minAmount &&
                                            Prodprice <= snapOptions.plans[snapOptions.plans.length - 1].maxAmount
                                        ) {
                                            var SnapWidgetDiv = document.createElement('div');
                                            SnapWidgetDiv.className = 'snap_dp_list';
                                            SnapWidgetDiv.innerHTML =
                                                snapOptions.widgetPriceBreakdown &&
                                                snapOptions.widgetPriceBreakdown !== 'undefined'
                                                    ? getCategoryWidgetHtml(Prodprice, divId)
                                                    : snapOptions.categoryWidgetHtml;
                                            k.querySelector(divId + ' ' + snapOptions.categoryWidgetDivId).after(
                                                SnapWidgetDiv
                                            );
                                            let popupType = 3;
                                            getDownPaymentAndEmi(Prodprice);
                                            if (
                                                snapOptions.categoryPopupType &&
                                                snapOptions.categoryPopupType !== 'undefined'
                                            ) {
                                                popupType = parseInt(snapOptions.categoryPopupType);
                                            }
                                            k.querySelector('.snap_dp_list' + ' ' + '.dp-collection-price').innerText =
                                                parseNum(emi);
                                            k.querySelector(
                                                '.snap_dp_list' + ' ' + '.dp-collection-price'
                                            ).setAttribute('data-price', parseNum(Prodprice));
                                        }
                                    }, 2000);
                                }
                            );
                        }
                    }
                } catch (e) {
                    console.log(e);
                }
            }
        });
    }
    if (snapOptions.categoryPagination && snapOptions.categoryPagination !== 'undefined') {
        var Pagination = document.querySelector(snapOptions.categoryPagination);
        if (Pagination) {
            Pagination.addEventListener('click', function (event) {
                setTimeout(() => {
                    collectionList(divId);
                }, 2000);
            });
        }
    }
}
function addingInputFieldKeyup() {
    if (document.querySelector('#snap-modalon_page #fname')) {
        document.querySelector('#snap-modalon_page #fname').addEventListener('click', function (evt) {
            if (snapOptions.isPosthogEventRequired && snapOptions.isPosthogEventRequired === 'true') {
                captureEvents('2.0_first_name_clicked', {
                    merchant_id: snapOptions.mid,
                    merchant_name: snapOptions.merchantName
                });
            }
        });
        document.querySelector('#snap-modalon_page #fname').addEventListener('keyup', function (evt) {
            var fname = document.querySelector('#snap-modalon_page #fname').value;
            document.querySelector('#snap-modalon_page #fname').setAttribute('maxLength', 25);
            document.querySelector('#snap-modalon_page #fname').value = fname
                .replace(/[^a-zA-Z]/g, '')
                .replace(/(\..*)\./g, '$1');
            if (fname == '') {
                document.getElementById('err_fname').innerText = 'Please Check First Name';
                return false;
            } else {
                document.getElementById('err_fname').innerHTML = '';
                document.querySelector('#snap-modalon_page #fname').classList.remove('error_field');
                return false;
            }
        });
    }

    if (document.querySelector('#snap-modalon_page #lname')) {
        document.querySelector('#snap-modalon_page #lname').addEventListener('click', function (evt) {
            if (snapOptions.isPosthogEventRequired && snapOptions.isPosthogEventRequired === 'true') {
                captureEvents('2.0_last_name_clicked', {
                    merchant_id: snapOptions.mid,
                    merchant_name: snapOptions.merchantName
                });
            }
        });
        document.querySelector('#snap-modalon_page #lname').addEventListener('keyup', function (evt) {
            var lname = document.querySelector('#snap-modalon_page #lname').value;
            document.querySelector('#snap-modalon_page #lname').setAttribute('maxLength', 25);
            document.querySelector('#snap-modalon_page #lname').value = lname
                .replace(/[^a-zA-Z]/g, '')
                .replace(/(\..*)\./g, '$1');
            var fname = document.querySelector('#snap-modalon_page #fname').value;
            if (fname == '') {
                document.getElementById('err_fname').innerHTML = 'Please Check First Name';
            }
            if (lname == '') {
                document.getElementById('err_lname').innerHTML = 'Please Check Last Name';
                return false;
            } else {
                document.getElementById('err_lname').innerHTML = '';
                document.querySelector('#snap-modalon_page #lname').classList.remove('error_field');
                return false;
            }
        });
    }
    if (document.querySelector('#snap-modalon_page #mnumber')) {
        document.querySelector('#snap-modalon_page #mnumber').addEventListener('click', function (evt) {
            if (snapOptions.isPosthogEventRequired && snapOptions.isPosthogEventRequired === 'true') {
                captureEvents('2.0_phone_number_clicked', {
                    merchant_id: snapOptions.mid,
                    merchant_name: snapOptions.merchantName
                });
            }
        });
        document.querySelector('#snap-modalon_page #mnumber').addEventListener('keyup', function (evt) {
            var firstChar = document.querySelector('#snap-modalon_page #mnumber').value.charAt(0);
            if (firstChar <= '5' && firstChar >= '0') {
                var phoneNumber = document.querySelector('#snap-modalon_page #mnumber').value;
                document.querySelector('#snap-modalon_page #mnumber').value = phoneNumber
                    .replace(/[0-5]/g, '')
                    .replace(/(\..*)\./g, '$1');
            }
            if (evt.keyCode < 48 || evt.keyCode > 57) {
                var phoneNumber = document.querySelector('#snap-modalon_page #mnumber').value;
                document.querySelector('#snap-modalon_page #mnumber').value = phoneNumber
                    .replace(/[^0-9]/g, '')
                    .replace(/(\..*)\./g, '$1');
            }
            if (document.querySelector('#snap-modalon_page #fname')) {
                var fname = document.querySelector('#snap-modalon_page #fname').value;
                if (fname == '') {
                    document.getElementById('err_fname').innerHTML = 'Please Check First Name';
                }
                var lname = document.querySelector('#snap-modalon_page #lname').value;
                if (lname == '') {
                    document.getElementById('err_lname').innerHTML = 'Please Check Last Name';
                }
            }
        });
    }
}
function fetchDataForShopify(minCartLoadPage = false) {
    let delivery_amount = 0;
    //adding delivery charge for express
    if (snapOptions.addingDeliveryAmountExpress && snapOptions.addingDeliveryAmountExpress !== 'undefined') {
        delivery_amount = parseInt(snapOptions.addingDeliveryAmountExpress);
    }
    if (snapOptions.merchantCartFetch && snapOptions.merchantCartFetch !== 'undefined') {
        eval(snapOptions.merchantCartFetch);
        return;
    }
    fetch(window.Shopify.routes.root + 'cart.js')
        .then((response) => response.json())
        .then((data) => {
            if (data.total_price) {
                if (snapOptions.isSubtotalVisible && snapOptions.isSubtotalVisible !== 'undefined')
                    snapOptions.isSubtotalVisible = parseInt(data.total_price / 100);
                if (minCartLoadPage) {
                    addminCartLoadPage();
                }
                miniCartQuantity = data.item_count;
                if (snapOptions.deliveryAmount && snapOptions.deliveryAmount !== 'undefined') {
                    delivery_amount = addDeliveryAmouunt(data.item_count);
                }
                productdesc = {
                    snapOrderValue: data.total_price / 100 + delivery_amount * data.item_count,
                    merchantId: snapOptions.mid
                };
                snapProducts.clear();
                for (i = 0; i < data.items.length; i++) {
                    var items = {
                        sku: '',
                        name: data.items[i].product_title,
                        quantity: data.items[i].quantity,
                        unit_price: data.items[i].final_price / 100,
                        imei1: data.items[i].variant_id,
                        source: 'cart'
                    };
                    const gmtProps = {
                        ...items,
                        product_id: data.items[i].product_id,
                        image_url: data.items[i].image,
                        product_url: data.items[i].url
                    };
                    if (snapOptions.personaliseDivId && snapOptions.personaliseDivId !== 'undefined') {
                        if (data.items[i].properties) {
                            items['product_comment'] = data.items[i].properties;
                        }
                    }
                    snapProducts.push(items);
                    webEngageInfo.push(gmtProps);
                    if (snapOptions.onWebsiteCoupon && snapOptions.onWebsiteCoupon !== 'undefined') {
                        if (data.items[i].discounts && data.items[i].discounts.length > 0) {
                            onWebsiteCouponApplied = data.items[i].discounts[0].title;
                        } else {
                            onWebsiteCouponApplied = null;
                        }
                    }
                }
            }
            handleServiceWorker(snapProducts, productdesc, 'checkcokiee');
        });
}

function createCartFromCartPage() {
    fetchDataForShopify();
}
function createCart() {
    snapProducts.clear();
    webEngageInfo.clear();
    let elemqty = 1;
    if (window.location.href.includes(snapOptions.cartUrl)) {
        createCartFromCartPage();
        isMiniCartPopupOpen = false;
    } else {
        let mini_cart = getByIdOrClassName(snapOptions.miniCartDivId);
        if (mini_cart) {
            isMiniCartPopupOpen = true;
            createCartFromMiniCart();
        } else {
            isMiniCartPopupOpen = false;
            if (snapQuantity) {
                elemqty = snapQuantity;
            }
            var fprice = '';
            var priceF = '';
            if (snapOptions.findAmount && snapOptions.findAmount !== 'undefined') {
                priceF = eval(snapOptions.findAmount);
            } else {
                if (getByIdOrClassName(snapOptions.priceSaleDivId)) {
                    priceF = getByIdOrClassName(snapOptions.priceSaleDivId).innerText;
                } else {
                    priceF = getByIdOrClassName(snapOptions.priceDivId).innerText;
                }
            }
            fprice = parseNum(priceF);
            var name = getByIdOrClassName(snapOptions.productNameDivId).innerText;
            var queryString = window.location.search;
            var urlParams = new URLSearchParams(queryString);
            var variant = urlParams.get('variant');
            if (variant) {
                var fvariant = variant;
            } else {
                if (snapOptions.findVariantId.length > 0 && snapOptions.findVariantId !== 'undefined') {
                    var fvariant = eval(snapOptions.findVariantId);
                } else {
                    var e = document.querySelector(`${snapOptions.variantDivId} select[name="id"]`);
                    if (e == null) {
                        var e = document.querySelector(`${snapOptions.variantDivId} input[name="id"]`);
                    }
                    if (e) var fvariant = e.value;
                    else addOutOfStockError();
                }
            }
            var items = {
                sku: '',
                name: name,
                quantity: elemqty,
                unit_price: fprice,
                imei1: fvariant,
                source: 'pdp'
            };
            snapProducts.push(items);
            const gmtProps = {
                ...items,
                product_id: eval(snapOptions.productId),
                image_url: eval(snapOptions.productImgUrl),
                product_url: window.location.href
            };
            webEngageInfo.push(gmtProps);
            //adding delivery charge for express
            let delivery_amount = 0;
            if (snapOptions.addingDeliveryAmountExpress && snapOptions.addingDeliveryAmountExpress !== 'undefined') {
                delivery_amount = parseInt(snapOptions.addingDeliveryAmountExpress);
            }
            if (snapOptions.deliveryAmount && snapOptions.deliveryAmount !== 'undefined') {
                delivery_amount = addDeliveryAmouunt(elemqty);
            }
            productdesc = {
                snapOrderValue: elemqty * (delivery_amount + fprice),
                merchantId: snapOptions.mid
            };
            handleServiceWorker(snapProducts, productdesc, 'checkcokiee');
        }
    }
}
function checkOutOfStock() {
    if (getByIdOrClassName(snapOptions.checkoutBtnId)) {
        let add_Cart_btn = getByIdOrClassName(snapOptions.checkoutBtnId).innerText;
        let isCheckOutOfStock = false;
        if (snapOptions.checkSoldOutProduct && snapOptions.checkSoldOutProduct !== 'undefined') {
            let element = getByIdOrClassName(snapOptions.checkSoldOutProduct);
            if (element && element.innerText.toLowerCase() === snapOptions.outOfStock) {
                isCheckOutOfStock = true;
            }
            if (snapOptions.productNotAvailable && snapOptions.productNotAvailable !== 'undefined') {
                let element = getByIdOrClassName(snapOptions.checkSoldOutProduct);
                if (element && element.innerText.toLowerCase() === snapOptions.productNotAvailable) {
                    isCheckOutOfStock = true;
                }
            }
        }
        if (snapOptions.checkDisableCheckout && snapOptions.checkDisableCheckout !== 'undefined') {
            if (add_Cart_btn === '') {
                add_Cart_btn = 'check disable checkout btn';
            }
        }
        if (add_Cart_btn) {
            let isProductOutOfStockAvailable = false;
            try {
                if (snapProdDetail && snapProdDetail.available) {
                    if (snapProdDetail.available === false) {
                        isProductOutOfStockAvailable = true;
                    }
                }
            } catch (e) {}
            if (snapOptions.checkVariant && snapOptions.checkVariant !== 'undefined') {
                var queryString = window.location.search;
                var urlParams = new URLSearchParams(queryString);
                var variant = urlParams.get('variant');
                if (!variant) {
                    isProductOutOfStockAvailable = true;
                }
            }
            if (snapOptions.checkDisableCheckout && snapOptions.checkDisableCheckout !== 'undefined') {
                if (document.querySelector(snapOptions.checkDisableCheckout)) {
                    isProductOutOfStockAvailable = true;
                }
            }
            if (snapOptions.outOfStockTrim && snapOptions.outOfStockTrim !== 'undefined') {
                add_Cart_btn = add_Cart_btn.trim();
            }
            if (
                add_Cart_btn.toLowerCase() === 'out of stock' ||
                add_Cart_btn.toLowerCase() === snapOptions.outOfStock ||
                isCheckOutOfStock ||
                isProductOutOfStockAvailable
            ) {
                addOutOfStockError();
            }
        }
    }
}

async function handlesubmit(productdesc) {
    if (document.querySelector('#snap-modalon_page #fname'))
        var fname = document.querySelector('#snap-modalon_page #fname').value;
    if (document.querySelector('#snap-modalon_page #lname'))
        var lname = document.querySelector('#snap-modalon_page #lname').value;
    var phoneNumber = document.querySelector('#snap-modalon_page #mnumber').value;

    if (fname === '' || lname === '' || phoneNumber === '' || !validatePhoneNumbers(phoneNumber)) {
        if (fname === '') {
            if (document.getElementById('err_fname')) {
                document.getElementById('err_fname').innerText = 'Please Check First Name';
                document.querySelector('#snap-modalon_page #fname').classList.add('error_field');
            }
            return false;
        }
        if (fname != '') {
            if (document.getElementById('err_fname')) {
                document.getElementById('err_fname').innerText = '';
                document.querySelector('#snap-modalon_page #fname').classList.remove('error_field');
            }
        }

        if (lname === '') {
            if (document.getElementById('err_lname')) {
                document.getElementById('err_lname').innerText = 'Please Check Last Name';
                document.querySelector('#snap-modalon_page #lname').classList.add('error_field');
            }
            return false;
        }
        if (lname != '') {
            if (document.getElementById('err_lname')) {
                document.getElementById('err_lname').innerText = '';
                document.querySelector('#snap-modalon_page #lname').classList.remove('error_field');
            }
        }

        if (phoneNumber === '') {
            document.getElementById('err_num').innerText = 'Please Check Mobile Number';
            document.querySelector('#snap-modalon_page #mnumber').classList.add('error_field');
            return false;
        }
        if (!validatePhoneNumbers(phoneNumber)) {
            document.getElementById('err_num').innerText = 'Please Check Mobile Number';
            document.querySelector('#snap-modalon_page #mnumber').classList.add('error_field');
            return false;
        }
        if (phoneNumber !== '' && validatePhoneNumbers(phoneNumber)) {
            document.getElementById('err_num').innerText = '';
            document.querySelector('#snap-modalon_page #mnumber').classList.remove('error_field');
        }
        return false;
    } else {
        document.querySelector('#snap-modalon_page #mnumber').classList.remove('error_field');
        if (document.querySelector('#snap-modalon_page #lname'))
            document.querySelector('#snap-modalon_page #lname').classList.remove('error_field');
        if (document.querySelector('#snap-modalon_page #fname'))
            document.querySelector('#snap-modalon_page #fname').classList.remove('error_field');
        if (document.querySelector('.snapLoader')) {
            document.querySelector('.snapLoader').setAttribute('style', 'display:block;');
        }
        if (document.querySelector('.snapmint_lowest_emi')) {
            document.querySelector('.snapmint_lowest_emi').setAttribute('style', 'display:none;');
        }
        if (snapOptions.isPosthogEventRequired && snapOptions.isPosthogEventRequired === 'true') {
            captureEvents('2.0_phone_submit_clicked', {
                merchant_id: snapOptions.mid,
                merchant_name: snapOptions.merchantName
            });
        }
        var orderVal = productdesc.snapOrderValue;
        var saPAttributes = getCookieAttributes('_shopify_sa_p');
        var saTAttributes = getCookieAttributes('_shopify_sa_t');
        var c_snap_landing_page = getDynamicJsCookie('snap_landing_page');
        var c_snap_referrer_url = getDynamicJsCookie('snap_referrer_url');
        var gaAttribute = getCookieAttributes(snapOptions.gaAttributeKey);
        var sessionIdAttribute = getCookieAttributes(snapOptions.sessionIdAttributeKey);
        var data = {
            merchant_confirmation_url: productdesc.merchant_confirmation_url,
            merchant_failure_url: productdesc.merchant_failure_url,
            merchant_id: productdesc.merchantId,
            order_id: '',
            order_value: orderVal,
            first_name: fname,
            middle_name: '',
            last_name: lname,
            email: '',
            mobile: phoneNumber,
            products: snapProducts,
            source: snapProducts[0]['source'],
            _orig_referrer: c_snap_referrer_url,
            _landing_page: c_snap_landing_page,
            _shopify_sa_p: saPAttributes.value,
            _shopify_sa_t: saTAttributes.value,
            merchant_confirmation_url: snapOptions.merchant_confirmation_url,
            merchant_failure_url: snapOptions.merchant_failure_url,
            client_id: gaAttribute.value ?? null,
            session_id: sessionIdAttribute.value ?? null
        };
        const transformPayload = (payload) =>{
            if (snapOptions.checkoutVersion !== '3') {
                return payload;
            }
            if (payload.merchant_confirmation_url === 'undefined') {
                payload.merchant_confirmation_url = '';
            }
            if (payload.merchant_failure_url === 'undefined') {
                payload.merchant_failure_url = '';
            }
            return payload
        }
        data = transformPayload(data);
        if (snapOptions.isCashbackEnabled && snapOptions.isCashbackEnabled === 'true') {
            const promoId = cashbackCache?.[snapOrderValue]?.cashbackPromoId;

            if (promoId) data.promo_ids = [cashbackCache[snapOrderValue].cashbackPromoId];
        }
        if (
            discountedOrderValue &&
            snapDiscountCode &&
            snapOptions.isCashbackCoupon &&
            snapOptions.isCashbackCoupon === 'true'
        ) {
            discountedOrderValue = Math.floor(discountedOrderValue);
            if (snapOptions.onWebsiteCoupon && snapOptions.onWebsiteCoupon !== 'undefined') {
                if (onWebsiteCouponApplied) {
                    data.order_value = snapOrderValue;
                } else {
                    data.order_value = discountedOrderValue;
                }
            } else {
                data.order_value = discountedOrderValue;
            }
            data['coupon'] = snapDiscountCode;
        }
        if (snapOptions.autoMaticCoupon && snapOptions.autoMaticCoupon !== 'undefined') {
            if (!data['coupon']) {
                data['coupon'] = getAutoMaticCoupon(orderVal);
            }
        }
        if (snapUnleashFlag) {
            data['udf1'] = snapUnleashFlag;
        }
        if (snapOptions.onWebsiteCoupon && snapOptions.onWebsiteCoupon !== 'undefined') {
            if (onWebsiteCouponApplied) {
                data['coupon'] = onWebsiteCouponApplied;
            }
        }
        if (snapOptions.shippingFee && snapOptions.shippingFee !== 'undefined') {
            let localQuantity = snapQuantity;
            if (
                window.location.href.includes(snapOptions.cartUrl) ||
                getByIdOrClassName(snapOptions.miniCartDivId) ||
                snapProducts.length > 0
            ) {
                localQuantity = 0;
                for (let i = 0; i < snapProducts.length; i++) {
                    localQuantity += snapProducts[i].quantity;
                }
            }
            let checkMinValue = '';
            if (snapOptions.minForDelivery && snapOptions.minForDelivery !== 'undefined')
                checkMinValue = snapOptions.minForDelivery;
            if (
                snapOptions.addingDeliveryMaxAmountExpress &&
                snapOptions.addingDeliveryMaxAmountExpress !== 'undefined'
            )
                checkMinValue = snapOptions.addingDeliveryMaxAmountExpress;
            if (parseInt(productdesc.snapOrderValue) < parseInt(checkMinValue)) {
                data['shipping_id'] = snapOptions.shippingId;
                if (snapOptions.shippingFeeUnit && snapOptions.shippingFeeUnit !== 'undefined') {
                    data['shipping_fee'] = snapOptions.shippingFeeUnit;
                } else {
                    data['shipping_fee'] = parseInt(snapOptions.shippingFee) * localQuantity;
                }
                data['shipping_title'] = snapOptions.shippingTitle;
            }
        }
        let resp = await getCheckoutUrl(data);
        if (resp.status === 'Success') {
            if (snapOptions.isGTMEnable && snapOptions.isGTMEnable !== 'undefined') {
                dataLayer.push({
                    event: 'cart_created',
                    values: {
                        merchant_id: productdesc.merchantId
                    },
                    page_location: window.location.href,
                    page_path: window.location.pathname,
                    merchant_name: snapOptions.merchantName,
                    mobile: phoneNumber,
                    order_value: orderVal.toString(),
                    first_name: fname,
                    last_name: lname,
                    orig_referrer: c_snap_referrer_url,
                    landing_page: c_snap_landing_page,
                    shopify_sa_p: saPAttributes.value,
                    shopify_sa_t: saTAttributes.value
                });
            }
            webEngageEvent('Mobile_Added_Snapmint', {
                mobile: phoneNumber,
                order_value: orderVal.toString(),
                first_name: fname,
                last_name: lname,
                promo_code: data['coupon'] ? data['coupon'] : '',
                currency: 'INR'
            });
            var iframeUrl = resp.redirect_url;

            if (
                iframeUrl.includes('checkout.snapmint.com') ||
                iframeUrl.includes('checkoutv2.snapmint.com') ||
                iframeUrl.includes('pay.snapmint.com')
            ) {
                if (isSnapMerchantJSMobile) {
                    windowPopup = window.open(iframeUrl, 'mozillaWindow', windowFeaturesSnapmint);
                    let registerData = {
                        merchant_id: productdesc.merchantId,
                        fname: fname,
                        lname: lname,
                        phoneNumber: phoneNumber,
                        orderVal: orderVal
                    };
                    if (
                        discountedOrderValue &&
                        snapDiscountCode &&
                        snapOptions.isCashbackCoupon &&
                        snapOptions.isCashbackCoupon === 'true'
                    ) {
                        registerData['coupon'] = snapDiscountCode;
                    }
                    handleServiceWorker(registerData, 'setcokiee');

                    var encrypted = CryptoJS.AES.encrypt(iframeUrl, encryptionKeyCryptoJs);
                    window.localStorage.setItem('snapminturl', encrypted);
                    checkpopup(windowPopup, iframeUrl);
                } else {
                    openCheckV2Iframe(iframeUrl, fname, lname, phoneNumber);
                    let registerData = {
                        merchant_id: productdesc.merchantId,
                        fname: fname,
                        lname: lname,
                        phoneNumber: phoneNumber,
                        orderVal: orderVal
                    };
                    if (
                        discountedOrderValue &&
                        snapDiscountCode &&
                        snapOptions.isCashbackCoupon &&
                        snapOptions.isCashbackCoupon === 'true'
                    ) {
                        registerData['coupon'] = snapDiscountCode;
                    }
                    handleServiceWorker(registerData, 'setcokiee');
                    handleCloseButtonIframe();
                    var encrypted = CryptoJS.AES.encrypt(iframeUrl, encryptionKeyCryptoJs);
                    window.localStorage.setItem('snapminturl', encrypted);
                }
            } else {
                windowPopup = window.open(iframeUrl, 'mozillaWindow', windowFeaturesSnapmint);
                let registerData = {
                    merchant_id: productdesc.merchantId,
                    fname: fname,
                    lname: lname,
                    phoneNumber: phoneNumber,
                    orderVal: orderVal
                };
                if (
                    discountedOrderValue &&
                    snapDiscountCode &&
                    snapOptions.isCashbackCoupon &&
                    snapOptions.isCashbackCoupon === 'true'
                ) {
                    registerData['coupon'] = snapDiscountCode;
                }
                handleServiceWorker(registerData, 'setcokiee');

                var encrypted = CryptoJS.AES.encrypt(iframeUrl, encryptionKeyCryptoJs);
                window.localStorage.setItem('snapminturl', encrypted);
                checkpopup(windowPopup, iframeUrl);

                checkAuthenticated(resp.id, resp.token);
            }
        } else {
            addOutOfStockError();
        }
    }
}

async function handleServiceWorker(registerData, productdesc, typeofdata) {
    try {
        if (typeofdata === 'checkcokiee') {
            const isMiniCart = getByIdOrClassName(snapOptions.miniCartDivId);
            if (
                getByIdOrClassName(snapOptions.checkoutBtnId) &&
                !isMiniCart &&
                !sessionStorage.getItem('sizeslected')
            ) {
                let add_Cart_btn = getByIdOrClassName(snapOptions.checkoutBtnId).innerText;
                if (snapOptions.checkDisableCheckout && snapOptions.checkDisableCheckout !== 'undefined') {
                    if (add_Cart_btn === '') {
                        add_Cart_btn = 'check disable checkout btn';
                    }
                }
                if (add_Cart_btn) {
                    let isCheckOutOfStock = false;
                    if (snapOptions.checkSoldOutProduct && snapOptions.checkSoldOutProduct !== 'undefined') {
                        let element = getByIdOrClassName(snapOptions.checkSoldOutProduct);
                        if (element && element.innerText.toLowerCase() === snapOptions.outOfStock) {
                            isCheckOutOfStock = true;
                        }
                        if (snapOptions.productNotAvailable && snapOptions.productNotAvailable !== 'undefined') {
                            let element = getByIdOrClassName(snapOptions.checkSoldOutProduct);
                            if (element && element.innerText.toLowerCase() === snapOptions.productNotAvailable) {
                                isCheckOutOfStock = true;
                            }
                        }
                    }
                    if (snapOptions.checkVariant && snapOptions.checkVariant !== 'undefined') {
                        var queryString = window.location.search;
                        var urlParams = new URLSearchParams(queryString);
                        var variant = urlParams.get('variant');
                        if (!variant) {
                            isCheckOutOfStock = true;
                        }
                    }
                    if (snapOptions.checkDisableCheckout && snapOptions.checkDisableCheckout !== 'undefined') {
                        if (document.querySelector(snapOptions.checkDisableCheckout)) {
                            isCheckOutOfStock = true;
                        }
                    }
                    if (
                        add_Cart_btn.toLowerCase() === 'out of stock' ||
                        add_Cart_btn.toLowerCase() === snapOptions.outOfStock ||
                        isCheckOutOfStock
                    ) {
                        addOutOfStockError();
                        return 400;
                    }
                }
            }
            var snapDynamicJsCookie = getDynamicJsCookie('snapmintDynamicJscookie');
            if (snapDynamicJsCookie) {
                var decrypted = CryptoJS.AES.decrypt(snapDynamicJsCookie, encryptionKeyCryptoJs);
                let resp = JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
                if (resp) {
                    prefillUserValues(resp);
                }
            }
            return 200;
        } else {
            var encrypted = CryptoJS.AES.encrypt(JSON.stringify(registerData), encryptionKeyCryptoJs);
            setDynamicJsCookie('snapmintDynamicJscookie', encrypted);
            return 400;
        }
    } catch (error) {
        return 400;
    }
}

const prefillUserValues = (userData) => {
    try {
        let merchantId = userData?.merchant_id;
        if (!merchantId) {
            return;
        }
        if (merchantId !== snapOptions.mid) {
            return;
        }
        let fName = document.querySelector('#snap-modalon_page #fname');
        let lName = document.querySelector('#snap-modalon_page #lname');
        let phoneNum = document.querySelector('#snap-modalon_page #mnumber');
        if (fName && userData?.fname) {
            fName.value = userData?.fname;
        }
        if (lName && userData?.lname) {
            lName.value = userData?.lname;
        }
        if (phoneNum && userData?.phoneNumber) {
            if (validatePhoneNumbers(userData?.phoneNumber)) {
                phoneNum.value = userData?.phoneNumber;
            }
        }
    } catch (error) {
        console.error('Error in getting userData', error);
    }
};

