function checkpopup(windowPopup, iframeUrl) {
    if (windowPopup == null || typeof windowPopup == 'undefined') {
        windowPopup = window.open(iframeUrl, '_blank');
        if (windowPopup == null || typeof windowPopup == 'undefined') {
            if (document.querySelector('.snapmint_lowest_emi')) {
                document.querySelector('.snapmint_lowest_emi').style.display = 'none';
            }
            if (document.getElementById('snap-modalon_page')) {
                document.getElementById('snap-modalon_page').style.display = 'block';
            }
            if (document.querySelector('.snapLoader')) {
                document.querySelector('.snapLoader').setAttribute('style', 'display:block;');
            }
            if (document.querySelector('.rotating_img_unrotate')) {
                let img_rotate = document.querySelector('.rotating_img_unrotate');
                img_rotate.classList.remove('rotating');
                document.querySelector('.snap_processing_text').style.display = 'none';
            }
            if (document.querySelector('.snap_emi_purchase_btn')) {
                document.querySelector('.snap_emi_purchase_btn').addEventListener('click', function () {
                    if (document.querySelector('.popup_blocker')) {
                        document.querySelector('.popup_blocker').style.display = 'block';
                    }
                    if (document.querySelector('.snapLoader')) {
                        document.querySelector('.snapLoader').setAttribute('style', 'display:none;');
                    }
                });
            }
        }
    } else {
        if (
            iframeUrl.includes('checkout.snapmint.com') ||
            iframeUrl.includes('checkoutv2.snapmint.com') ||
            iframeUrl.includes('pay.snapmint.com')
        ) {
            closeCheckV2Iframe();
        } else {
            snapclosePopup();
        }
        window.localStorage.removeItem('autosnapminturl');
        windowPopup.focus();
    }
}

