Object.defineProperty(Array.prototype, 'clear', {
    value: function () {
        this.splice(0, this.length);
    }
});
function hostURL(version = 'v1') {
    return snapOptions.apiDomain + '/' + version;
}

function getCheckoutUrl(data) {
    if (snapOptions.checkoutVersion === '3') {
        return createV3Order(data);
    } else {
        return getToken(data);
    }
}

function getToken(data) {
    const url = `${hostURL()}/shopify_plugin/get_token`;
    const requestOptions = {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    };
    return fetch(url, requestOptions)
        .then((res) => res.json())
        .then((res) => {
            return res;
        });
}

function createV3Order(data) {
    const url = `${snapOptions.apisServiceDomain}/api/pub/v3/checkout-url?source=shopifyPdp`;
    const requestOptions = {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    };
    return fetch(url, requestOptions)
        .then((res) => res.json())
        .then((res) => {
            return {
                status: 'Success',
                redirect_url: res.url
            };
        });
}

function changeExpressWidget(urlToShowWidgetExpress) {
    let urlArray = urlToShowWidgetExpress.split(',');
    let isShowWidget = false;
    if (urlArray && urlArray.length) {
        urlArray.forEach((element) => {
            if (window.location.href.includes(element)) {
                isShowWidget = true;
            }
        });
    }
    return isShowWidget;
}
