function addListenerForRemoveMiniCartFn() {
    let allElement = document.querySelectorAll(snapOptions.removeMiniCartWidget);
    if (allElement) {
        allElement.forEach((element) => {
            element.addEventListener('click', () => {
                if (snapOptions.isMultiCheckAjax && snapOptions.isMultiCheckAjax !== 'undefined') {
                    let id = setTimeout(() => {
                        MiniCartOpen(snapOptions.isMultiCheckAjax, true);
                        clearTimeout(id);
                    }, 2000);
                }
                let widget = document.querySelector('.snap_emi_txt_minicart');
                if (widget) {
                    widget.parentNode.removeChild(widget);
                    getQuantity(false);
                    loadOnPage();
                } else {
                    if (snapOptions.isMinCartRemoveReload && snapOptions.isMinCartRemoveReload !== 'undefined') {
                        getQuantity(false);
                        loadOnPage();
                    }
                }
            });
        });
    }
}
function removeMiniCartWidgetFn() {
    let allElement = document.querySelectorAll(snapOptions.removeMiniCartWidget);
    if (allElement) {
        allElement.forEach((element) => {
            let widget = document.querySelector('.snap_emi_txt_minicart');
            if (widget) {
                widget.parentNode.removeChild(widget);
            }
        });
    }
}
function checkWhichWidgetToLoadMiniCart(miniCartWidgetExpressUrl) {
    let value = false;
    let allElement = document.querySelectorAll(miniCartWidgetExpressUrl);
    if (allElement.length > 0) {
        allElement.forEach((element) => {
            let list = snapOptions.miniCartWidgetShowText.split(',');
            list.forEach((item) => {
                if (element.href) {
                    if (element.href.includes(item)) {
                        value = true;
                    }
                }
            });
        });
    }
    return value;
}
function createCartFromMiniCart(minCartLoadPage = false) {
    fetchDataForShopify(minCartLoadPage);
    if (snapOptions.closeMiniCartDrawer && snapOptions.closeMiniCartDrawer !== 'undefined') {
        return;
    }
    var WrapCLose = document.querySelector("button[data-drawer-id='sidebar-cart']");
    if (!WrapCLose) {
        WrapCLose = document.querySelector('#CartDrawer.drawer--is-open .drawer__close-button');
    }
    if (snapOptions.closeMiniCart && snapOptions.closeMiniCart !== 'undefined') {
        WrapCLose = document.querySelector(snapOptions.closeMiniCart);
    }
    if (WrapCLose) {
        WrapCLose.click();
    }
}
function miniCartQuickViewFn() {
    if (snapOptions.miniCartQuickView && snapOptions.miniCartQuickView !== 'undefined') {
        if (document.querySelector(snapOptions.miniCartQuickView)) {
            if (snapOptions.isQuickViewCheckout && snapOptions.isQuickViewCheckout !== 'undefined') {
                addOnClickForCheckingQuickView();
            }
        }
    }
}
function addOnClickForCheckingQuickView() {
    const element = document.querySelectorAll(snapOptions.isQuickViewCheckout);
    if (element) {
        element.forEach((element) => {
            element.addEventListener('click', () => {
                let counter = 1;
                let id = setInterval(() => {
                    counter++;
                    if (counter === 10) {
                        clearInterval(id);
                    }
                    let checkoutBtn = document.querySelectorAll(snapOptions.newCheckoutForQuickView);
                    if (checkoutBtn) {
                        clearInterval(id);
                        MiniCartOpen(snapOptions.newCheckoutForQuickView, true, true);
                    }
                }, 1000);
            });
        });
    }
}
function changeMiniCartOrderValue() {
    if (getByIdOrClassName(snapOptions.miniCartDivId)) {
        if (snapOptions.onWebsiteCoupon && snapOptions.onWebsiteCoupon !== 'undefined') {
            snapOrderValue = productdesc.snapOrderValue;
            orderValueNotChange = productdesc.snapOrderValue;
        }
    }
}
